const problemsData = require('../../data/problems.json');

/**
 * Filters problems by difficulty and tags.
 * @param {Array} problems
 * @param {string|undefined} difficulty
 * @param {Array<string>|undefined} tags
 * @returns {Array}
 */
function filterProblems(problems, difficulty, tags) {
  return problems.filter(problem => {
    if (difficulty && problem.difficulty !== difficulty) return false;
    if (tags && tags.length > 0) {
      if (!problem.tags || !tags.every(t => problem.tags.includes(t))) return false;
    }
    return true;
  });
}

/**
 * Computes totals of problems by language and status.
 * @param {Array} problems
 * @returns {{componentLanguageTotals: Object, componentStatusTotals: Object}}
 */
function computeTotals(problems) {
  const componentLanguageTotals = {};
  const componentStatusTotals = {};

  problems.forEach(problem => {
    if (problem.language) {
      componentLanguageTotals[problem.language] = (componentLanguageTotals[problem.language] || 0) + 1;
    }
    if (problem.status) {
      componentStatusTotals[problem.status] = (componentStatusTotals[problem.status] || 0) + 1;
    }
  });

  return { componentLanguageTotals, componentStatusTotals };
}

/**
 * Lists problems with optional filtering, pagination, and component metadata.
 * @param {Object} params
 * @param {string} [params.difficulty] - difficulty filter
 * @param {Array<string>} [params.tags] - tags filter
 * @param {number} [params.limit] - max number of problems to return
 * @param {boolean} [params.includeComponents] - whether to include component totals metadata
 * @returns {Object} response with problems and optional metadata
 */
function listProblems({ difficulty, tags, limit, includeComponents }) {
  let filtered = filterProblems(problemsData, difficulty, tags);

  if (limit && Number.isInteger(limit) && limit > 0) {
    filtered = filtered.slice(0, limit);
  }

  const response = { problems: filtered };

  if (includeComponents) {
    const totals = computeTotals(filtered);
    response.componentLanguageTotals = totals.componentLanguageTotals;
    response.componentStatusTotals = totals.componentStatusTotals;
  }

  return response;
}

module.exports = {
  listProblems
};
